// Occupancy_Detection
void ODDemo_objInit(void)
{
    oddemo_dataPathObj.rangeAzimuthHeatMap = &oddemo_rangeAzimuthHeatMap[0];     /**< output range azimuth heatmap, array in format of (numInputRangeBins * nAzimuthBins).*/
}


/**
 *  @b Description
 *  @n
 *      Function to do Data Path Initialization on DSS.
 *
 *  @retval
 *      Not Applicable.
 */
int32_t MmwDemo_dssDataPathInit(void)
{

    // // Occupancy_Detection Object
    ODDemo_objInit();

	ODDemo_Feature_init();

	ODDemo_Decision_init();

	return 0;
}


/**
 *  @b Description
 *  @n
 *      Function to do ....
 *
 *  @retval
 *      Not Applicable.
 */
void MmwDemo_mboxReadTask()
{
	// case MMWDEMO_MSS2DSS_ODDEMO_ROW_NOISE
    /* 
	   Save ODDemo calculated row noise floor values. If this msg is not received,
       the code will assume that the FOV is EMPTY during the first several seconds
       and will calculate these values and print the CLI commands to the command window. 
	 */
	oddemo_row_init = ODDEMO_ROW_NOISE_FRAMES + 100;
}


/**
 *  @b Description
 *  @n
 *      Function to do Data Path Initialization on DSS.
 *
 *  @retval
 *      Not Applicable.
 */
int32_t MmwDemo_Init(void)
{
	set_CLIZoneDef();		// zoneDef
	set_CLIParms();			// 
	set_CLI_meanVec_stdVec();
	set_CLICoeffMatrix();	// CoeffMatrix
	set_CLIRowNoise();		// Row Noise value.

	oddemo_zone_pairs = oddemo_num_zones / 2;

	return 0;
}


/* -------------------------------------------------------------------------------
 *  @b Description
 *  @n
 *      Function to process Data Path events at runtime.
 -------------------------------------------------------------------------------*/
void MmwDemo_dssDataPathProcessEvents()
{
	MmwDemo_DSS_DataPathObj *dataPathObj;
	uint16_t chirpIndex;

	dataPathObj = &gMmwDssMCB.dataPathObj[gMmwDssMCB.subFrameIndx];

	// [240523_LEEYJ] DSP function Merge.
	
	for (chirpIndex = 0; chirpIndex < dataPathObj->numChirpsPerChirpEvent; chirpIndex++)
	{
		MmwDemo_processChirp();
	}

	MmwDemo_interFrameProcessing();
}


void MmwDemo_dssDataPathTask(void)
{
	int32_t       retVal = 0;

	MmwDemo_dssDataPathProcessEvents(); // if ((retVal = MmwDemo_dssDataPathProcessEvents()) < 0 )

}


void MmwDemo_dssInitTask(void)
{
	/* Create task to handle mailbox messges */
	MmwDemo_mboxReadTask();

	/* Data path Startup */
	MmwDemo_dssDataPathInit();

	/* Start data path task */
	MmwDemo_dssDataPathTask();
}


int dss_main(void)
{
	char i;
	char index;

	memset ((void*)&gMmwDssMCB, 0, sizeof(MmwDemo_DSS_MCB));

	for(i = 0; i < 4; i++)
	{
		index = pingPongId(i);
	}
	
	MmwDemo_Init();

	azimuthHeatMap_gen(); // randomNumber_gen();

	// numRangeBins = pow2roundup(numAdcSamples);
	memset(oddemo_previousHeatMap, 0, sizeof(oddemo_previousHeatMap));
	memcpy(oddemo_previousHeatMap, oddemo_rangeAzimuthHeatMap, sizeof(oddemo_previousHeatMap));

	MmwDemo_dssInitTask();

	system("PAUSE");
    return 0;
}